return [
  {
    json: {
      request_id: 'ARC-001',
      source: 'Email',
      raw_message: 'Hi, I tried logging in this morning and keep getting a 403 error. My account is arcvault.io/user/jsmith. This started after your update last Tuesday.',
    },
  },
  {
    json: {
      request_id: 'ARC-002',
      source: 'Web Form',
      raw_message: "We'd love to see a bulk export feature for our audit logs. We're a compliance-heavy org and this would save us hours every month.",
    },
  },
  {
    json: {
      request_id: 'ARC-003',
      source: 'Support Portal',
      raw_message: 'Invoice #8821 shows a charge of $1,240 but our contract rate is $980/month. Can someone look into this?',
    },
  },
  {
    json: {
      request_id: 'ARC-004',
      source: 'Email',
      raw_message: "I'm not sure if this is the right place to ask, but is there a way to set up SSO with Okta? We're evaluating switching our auth provider.",
    },
  },
  {
    json: {
      request_id: 'ARC-005',
      source: 'Web Form',
      raw_message: "Your dashboard stopped loading for us around 2pm EST. Checked our end - it's definitely on yours. Multiple users affected.",
    },
  },
];

function normalizeModelOutput(parsed) {
  const allowedCategories = [
    'Bug Report',
    'Feature Request',
    'Billing Issue',
    'Technical Question',
    'Incident/Outage',
  ];

  const allowedPriorities = ['Low', 'Medium', 'High'];
  const allowedUrgency = ['low', 'moderate', 'high'];

  if (!allowedCategories.includes(parsed.category)) {
    throw new Error(`Invalid category: ${parsed.category}`);
  }

  if (!allowedPriorities.includes(parsed.priority)) {
    throw new Error(`Invalid priority: ${parsed.priority}`);
  }

  const confidence = Number(parsed.confidence);
  if (!Number.isInteger(confidence) || confidence < 0 || confidence > 100) {
    throw new Error(`Invalid confidence: ${parsed.confidence}`);
  }

  if (!Array.isArray(parsed.identifiers)) {
    throw new Error('identifiers must be an array');
  }

  if (!allowedUrgency.includes(parsed.urgency_signal)) {
    throw new Error(`Invalid urgency_signal: ${parsed.urgency_signal}`);
  }

  if (typeof parsed.core_issue !== 'string' || !parsed.core_issue.trim()) {
    throw new Error('core_issue must be a non-empty string');
  }

  if (typeof parsed.summary !== 'string' || !parsed.summary.trim()) {
    throw new Error('summary must be a non-empty string');
  }

  return {
    category: parsed.category,
    priority: parsed.priority,
    confidence,
    core_issue: parsed.core_issue.trim(),
    identifiers: parsed.identifiers.map(String),
    urgency_signal: parsed.urgency_signal,
    summary: parsed.summary.trim(),
  };
}

return items.map((item, index) => {
  const content = item.json.choices?.[0]?.message?.content;

  if (!content) {
    throw new Error(`Missing model content for item ${index}`);
  }

  const parsed = JSON.parse(content);
  const normalized = normalizeModelOutput(parsed);
  const original = $('Load Sample Inputs').all()[index].json;

  return {
    json: {
      request_id: original.request_id,
      source: original.source,
      raw_message: original.raw_message,
      ...normalized,
    },
  };
});

function getRecommendedQueue(category, rawMessage) {
  const text = rawMessage.toLowerCase();

  if (category === 'Bug Report') {
    return 'Engineering';
  }

  if (category === 'Incident/Outage') {
    return 'Engineering';
  }

  if (category === 'Feature Request') {
    return 'Product';
  }

  if (category === 'Billing Issue') {
    return 'Billing';
  }

  if (category === 'Technical Question') {
    const securityKeywords = ['sso', 'okta', 'auth', 'authentication', 'saml', 'oauth', 'security'];
    if (securityKeywords.some((keyword) => text.includes(keyword))) {
      return 'IT/Security';
    }
    return 'Engineering';
  }

  return 'Human Review / Escalation';
}

function getBillingDiscrepancy(rawMessage) {
  const matches = [...rawMessage.matchAll(/\$([0-9,]+(?:\.[0-9]{2})?)/g)];
  if (matches.length < 2) {
    return 0;
  }

  const values = matches
    .map((match) => Number(match[1].replace(/,/g, '')))
    .filter((value) => !Number.isNaN(value));

  if (values.length < 2) {
    return 0;
  }

  return Math.abs(values[0] - values[1]);
}

return items.map((item) => {
  const record = item.json;
  const rawMessage = record.raw_message || '';
  const text = rawMessage.toLowerCase();

  const recommendedQueue = getRecommendedQueue(record.category, rawMessage);
  const escalationReasons = [];

  if ((record.confidence ?? 0) < 70) {
    escalationReasons.push('confidence below 70');
  }

  const outagePatterns = [
    'outage',
    'multiple users affected',
    'all users',
    'system down',
    'service down',
    'dashboard stopped loading',
    'down for everyone',
  ];

  if (outagePatterns.some((pattern) => text.includes(pattern))) {
    escalationReasons.push('possible outage or broad impact detected');
  }

  if (text.includes('multiple users affected')) {
    escalationReasons.push('multiple users affected');
  }

  if (record.category === 'Billing Issue') {
    const discrepancy = getBillingDiscrepancy(rawMessage);
    if (discrepancy > 500) {
      escalationReasons.push(`billing discrepancy exceeds threshold: $${discrepancy}`);
    }
  }

  const escalate = escalationReasons.length > 0;
  const finalQueue = escalate ? 'Human Review / Escalation' : recommendedQueue;

  return {
    json: {
      ...record,
      recommended_queue: recommendedQueue,
      final_queue: finalQueue,
      escalate,
      escalation_reasons: escalationReasons,
    },
  };
});

const records = $json.records || [];

return [
  {
    json: {
      fileName: 'outputs.json',
      fileContent: JSON.stringify(records, null, 2),
    },
  },
];
